const body = $input.first().json.body || $input.first().json;
const b = body;

if (!b.code || !b.nom || !b.description || !b.categorie) {
  return [{ json: { success: false, error: 'code, nom, description, categorie requis' } }];
}

return [{ json: {
  code: b.code,
  nom: b.nom,
  description: b.description,
  categorie: b.categorie,
  icon: b.icon || 'general',
  setupPrice: b.setupPrice || 0,
  monthlyPrice: b.monthlyPrice || 0,
  complexity: b.complexity || 'simple',
  workflowCount: b.workflowCount || 0,
  workflowTemplates: JSON.stringify(b.workflowTemplates || []),
  features: JSON.stringify(b.features || []),
  valid: true
} }];
